sql:
SELECT COUNT(*) AS total_matches_won_by_home
FROM matches
WHERE full_time_home_goals > full_time_away_goals;

external_knowledge:
; Winning matches refer to matches where a team scored more goals than the opposing team (full time result 'H' for home win or 'A' for away win); 
; A team's highest-scoring winning match is the match in which the team scored the most goals among all their winning matches; 
; Total goals scored by a team refers to the sum of goals scored by the team across all their winning matches.
